import{c as t,O as a,i as n,m as s}from"./chunks/framework.BWIk71Uc.js";const g=JSON.parse('{"title":"MySQL Integration Practical Tutorial (Chinese Version)","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/spring/mysql-integration/index.md","filePath":"en/notes/spring/mysql-integration/index.md","lastUpdated":1779888725000}'),i={name:"en/notes/spring/mysql-integration/index.md"};function r(o,e,l,c,d,h){return a(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1779888725000"},[...e[0]||(e[0]=[s(`<h1 id="mysql-integration-practical-tutorial-chinese-version" tabindex="-1">MySQL Integration Practical Tutorial (Chinese Version) <a class="header-anchor" href="#mysql-integration-practical-tutorial-chinese-version" aria-label="Permalink to “MySQL Integration Practical Tutorial (Chinese Version)”">​</a></h1><blockquote><p><strong>Target Audience</strong>: Learners who have already gotten Spring Cloud Alibaba microservices running (Nacos / Sentinel / OpenFeign are all working) but haven&#39;t yet connected a database.</p><p><strong>Learning Objective</strong>: After completing this tutorial, you will be able to independently complete the MySQL integration for stock-service and order-service, understand &quot;why each line of configuration and code is written that way&quot;, and be able to verbally explain the differences between optimistic and pessimistic locking, key pitfalls of transaction boundaries, and the value of Flyway and Testcontainers.</p><p><strong>Estimated Time</strong>: 6–10 hours (excluding Docker image downloads).</p><p><strong>Supporting Documentation</strong>:</p><ul><li>Design Document: <code>docs/superpowers/specs/2026-05-27-mysql-integration-design.md</code> (Explains clearly why each decision was made)</li><li>Implementation Plan: <code>docs/superpowers/plans/2026-05-27-mysql-integration.md</code> (29 atomic tasks, the source of &quot;reference answers&quot; for this tutorial)</li></ul><p><strong>How to Use This Tutorial</strong>: Each chapter follows the structure &quot;Objective → Concepts → Implementation → Key Points → Pitfalls → Self-Assessment&quot;. Read the concepts first, then code; after coding, think &quot;what would happen if I changed it to another way&quot; before reading the &quot;Key Points&quot; section to check your understanding.</p></blockquote><hr><h2 id="chapter-navigation" tabindex="-1">Chapter Navigation <a class="header-anchor" href="#chapter-navigation" aria-label="Permalink to “Chapter Navigation”">​</a></h2><table tabindex="0"><thead><tr><th>Chapter</th><th>Content</th></tr></thead><tbody><tr><td><a href="./">Overview</a></td><td>Preface, Big Picture (this article)</td></tr><tr><td><a href="./environment.html">Environment Preparation</a></td><td>Chapter 1 · MySQL, Nacos, Docker Environment Setup</td></tr><tr><td><a href="./database-design.html">Database Design</a></td><td>Chapters 2-3 · Maven Dependencies, Flyway Migrations</td></tr><tr><td><a href="./orm-integration.html">ORM Integration</a></td><td>Chapters 4-5 · Data Source Configuration, Entity Classes &amp; Mappers</td></tr><tr><td><a href="./lock-strategy.html">Lock Strategy Implementation</a></td><td>Chapters 6-8 · Strategy Pattern, Optimistic Lock, Pessimistic Lock</td></tr><tr><td><a href="./testing.html">Testing &amp; Acceptance</a></td><td>Chapters 9-15 · Refactoring, Exception Handling, Integration Tests, Acceptance</td></tr></tbody></table><hr><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to “Table of Contents”">​</a></h2><ul><li><a href="#preface-explaining-the-whole-thing">Preface: Explaining the Whole Thing</a></li><li><a href="#chapter-0-the-big-picture-what-to-do-and-why">Chapter 0 · The Big Picture: What to Do and Why</a></li><li><a href="./environment.html">Chapter 1 · Preparing the Development Environment</a></li><li><a href="./database-design.html">Chapter 2 · Maven Dependencies and Version Management</a></li><li><a href="./database-design.html">Chapter 3 · Managing Database Schema with Flyway</a></li><li><a href="./orm-integration.html">Chapter 4 · Configuring Data Sources and Separating Nacos Credentials</a></li><li><a href="./orm-integration.html">Chapter 5 · Entity Classes and Mappers (MyBatis-Plus Basics)</a></li><li><a href="./lock-strategy.html">Chapter 6 · Strategy Pattern for Switchable Locks</a></li><li><a href="./lock-strategy.html">Chapter 7 · How is Optimistic Lock &quot;Optimistic&quot;</a></li><li><a href="./lock-strategy.html">Chapter 8 · Pessimistic Lock and SELECT FOR UPDATE</a></li><li><a href="./testing.html">Chapter 9 · StockService Refactoring and Transaction Boundaries</a></li><li><a href="./testing.html">Chapter 10 · Global Exception Handler</a></li><li><a href="./testing.html">Chapter 11 · order-service Refactoring and Cross-Service Transaction Boundaries</a></li><li><a href="./testing.html">Chapter 12 · Writing Real Integration Tests with Testcontainers</a></li><li><a href="./testing.html">Chapter 13 · End-to-End Acceptance and Load Testing Comparison</a></li><li><a href="./testing.html">Chapter 14 · Pitfall Checklist and Root Cause Analysis</a></li><li><a href="./testing.html">Chapter 15 · What to Learn Next</a></li></ul><hr><h2 id="preface-explaining-the-whole-thing" tabindex="-1">Preface: Explaining the Whole Thing <a class="header-anchor" href="#preface-explaining-the-whole-thing" aria-label="Permalink to “Preface: Explaining the Whole Thing”">​</a></h2><p>The learning project has two microservices:</p><ul><li><strong>stock-service</strong>: Inventory service. Currently uses <code>ConcurrentHashMap&lt;String, Integer&gt;</code> to store 3 seed inventory items in memory (p1001 iPhone 15 / p1002 MacBook Pro / p1003 Apple Watch). Cleared on restart.</li><li><strong>order-service</strong>: Order service. Also uses <code>ConcurrentHashMap&lt;String, OrderCreateResult&gt;</code> to store orders in memory. Cleared on restart.</li></ul><p>&quot;Integrating MySQL&quot; might seem like just &quot;replacing the Map with a database&quot;, but to do it correctly requires thinking through a series of questions:</p><ol><li>Which ORM to use? (MyBatis-Plus / JPA / native MyBatis / JdbcTemplate?)</li><li>Should each service use the same database or different databases?</li><li>How to prevent overselling under high concurrency? (Optimistic lock or pessimistic lock? Or Redis distributed lock?)</li><li>How to evolve the table structure? (Manual SQL or Flyway/Liquibase?)</li><li>Where to store database credentials? (In application.yml or in Nacos?)</li><li>How to test database-related code? (H2 in-memory database / Mock / Testcontainers?)</li><li>How to handle transactions for cross-service operations like order creation + Feign calls to inventory?</li></ol><p>Design Document §13 provides conclusions and reasoning for all these decisions. The task of this tutorial is to guide you in <strong>personally implementing these decisions as code</strong>, and at each step tell you &quot;why writing it this way is better than that way&quot;.</p><hr><h2 id="chapter-0-·-the-big-picture-what-to-do-and-why" tabindex="-1">Chapter 0 · The Big Picture: What to Do and Why <a class="header-anchor" href="#chapter-0-·-the-big-picture-what-to-do-and-why" aria-label="Permalink to “Chapter 0 · The Big Picture: What to Do and Why”">​</a></h2><h3 id="_0-1-final-architecture" tabindex="-1">0.1 Final Architecture <a class="header-anchor" href="#_0-1-final-architecture" aria-label="Permalink to “0.1 Final Architecture”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Local MySQL 8.x Instance (localhost:3306)</span></span>
<span class="line"><span> ├─ stock_db    schema  ← stock-service uses stock_app account</span></span>
<span class="line"><span> │   ├─ stock_item        (product + inventory + version field)</span></span>
<span class="line"><span> │   └─ stock_deduct_log  (deduction audit log)</span></span>
<span class="line"><span> └─ order_db    schema  ← order-service uses order_app account</span></span>
<span class="line"><span>     └─ order_info        (order main table)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>stock-service  ──persistence──▶  stock_db   (MyBatis-Plus + HikariCP + Flyway)</span></span>
<span class="line"><span>order-service  ──persistence──▶  order_db   (MyBatis-Plus + HikariCP + Flyway)</span></span>
<span class="line"><span>                  Still calls stock-service via Feign, no cross-database reads</span></span></code></pre></div><h3 id="_0-2-seven-key-decisions" tabindex="-1">0.2 Seven Key Decisions <a class="header-anchor" href="#_0-2-seven-key-decisions" aria-label="Permalink to “0.2 Seven Key Decisions”">​</a></h3><table tabindex="0"><thead><tr><th>Decision</th><th>Our Choice</th><th>Brief Reason</th></tr></thead><tbody><tr><td>ORM Framework</td><td><strong>MyBatis-Plus 3.5.9</strong></td><td>Naturally fits with Spring Cloud Alibaba ecosystem; BaseMapper provides CRUD out of the box; Existing interceptors for optimistic lock/pagination/logical deletion</td></tr><tr><td>Database Partitioning</td><td><strong>One instance, multiple schemas + dual accounts</strong></td><td>Saves resources (no need to run two MySQL instances), but ensures logical isolation through account permissions</td></tr><tr><td>Anti-overselling Strategy</td><td><strong>Optimistic lock + pessimistic lock dual implementation, strategy pattern for hot switching</strong></td><td>Maximizes learning value, allows comparing two locks under the same dataset; leaves room for future Redis distributed lock extension</td></tr><tr><td>Migration Tool</td><td><strong>Flyway</strong></td><td>Brings database schema under version control, avoids &quot;code changed but schema didn&#39;t&quot; problems</td></tr><tr><td>Credential Management</td><td><strong>Nacos Configuration Center</strong></td><td>Database credentials don&#39;t go into git, password changes don&#39;t require service restart</td></tr><tr><td>Testing Strategy</td><td><strong>Testcontainers with real MySQL</strong></td><td>Avoids semantic differences with H2 (FOR UPDATE / utf8mb4 / AUTO_INCREMENT behavior differences) that create wrong muscle memory</td></tr><tr><td>Cross-Service Transactions</td><td><strong>No distributed transactions this time, errors bubble up</strong></td><td>Controls scope for this iteration; local message table Outbox pattern reserved for next iteration</td></tr></tbody></table><h3 id="_0-3-how-many-tables-will-we-create-why-these" tabindex="-1">0.3 How Many Tables Will We Create? Why These? <a class="header-anchor" href="#_0-3-how-many-tables-will-we-create-why-these" aria-label="Permalink to “0.3 How Many Tables Will We Create? Why These?”">​</a></h3><table tabindex="0"><thead><tr><th>Table</th><th>In Which Schema</th><th>Purpose</th><th>Why Needed</th></tr></thead><tbody><tr><td><code>stock_item</code></td><td>stock_db</td><td>Product + current inventory + optimistic lock version number</td><td>Replaces in-memory Map, stores &quot;product → inventory&quot; mapping</td></tr><tr><td><code>stock_deduct_log</code></td><td>stock_db</td><td>Audit log for each deduction (includes lock mode, duration)</td><td>For learning: compare success rate/RT of two locks; For operations: trace investigation</td></tr><tr><td><code>order_info</code></td><td>order_db</td><td>Order main table (includes degraded status)</td><td>Replaces in-memory Map, stores orders</td></tr></tbody></table><blockquote><p>💡 <strong>Think about it</strong>: Why not put the inventory table in order_db? Answer: Violates microservice principles. order-service shouldn&#39;t directly read stock-service data, must go through Feign. Even if both tables are physically in the same instance, logical isolation is required.</p></blockquote><h3 id="_0-4-data-flow-diagram" tabindex="-1">0.4 Data Flow Diagram <a class="header-anchor" href="#_0-4-data-flow-diagram" aria-label="Permalink to “0.4 Data Flow Diagram”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>User                gateway              order-service        Feign           stock-service</span></span>
<span class="line"><span> │                    │                      │                   │                   │</span></span>
<span class="line"><span> │── POST /order ────▶│                      │                   │                   │</span></span>
<span class="line"><span> │                    │── inject traceId ────▶                   │                   │</span></span>
<span class="line"><span> │                    │                      │                   │                   │</span></span>
<span class="line"><span> │                    │                      │── stockClient ───▶│── HTTP POST ─────▶│</span></span>
<span class="line"><span> │                    │                      │                   │                   │</span></span>
<span class="line"><span> │                    │                      │                   │              ┌────┴────┐</span></span>
<span class="line"><span> │                    │                      │                   │              │ @Tx Main│</span></span>
<span class="line"><span> │                    │                      │                   │              │ 1. Strategy│</span></span>
<span class="line"><span> │                    │                      │                   │              │   Deduct │</span></span>
<span class="line"><span> │                    │                      │                   │              │ 2. Write Log│</span></span>
<span class="line"><span> │                    │                      │                   │              └────┬────┘</span></span>
<span class="line"><span> │                    │                      │                   │                   │</span></span>
<span class="line"><span> │                    │                      │◀── 200/503/4xx ───│◀── Response ──────│</span></span>
<span class="line"><span> │                    │                      │                                       │</span></span>
<span class="line"><span> │                    │           ┌──────────┴──────────┐                            │</span></span>
<span class="line"><span> │                    │           │ @Tx Only insert     │                            │</span></span>
<span class="line"><span> │                    │           │   order             │                            │</span></span>
<span class="line"><span> │                    │           └──────────┬──────────┘                            │</span></span>
<span class="line"><span> │                    │                      │                                       │</span></span>
<span class="line"><span> │                    │◀── OrderCreateResult │                                       │</span></span>
<span class="line"><span> │◀── HTTP Response ──│                      │                                       │</span></span></code></pre></div><p>Note the three transaction boundaries:</p><ul><li>Stock-service&#39;s deduction + writing audit log = <strong>same transaction</strong> (either both succeed or both roll back)</li><li>When optimistic lock conflicts occur, the main transaction rolls back, but <strong>conflict logs are written by an independent Bean using REQUIRES_NEW</strong> (audit logs are preserved even if the main transaction rolls back)</li><li>Feign calls in order-service are <strong>outside the transaction</strong>, with local transactions only covering inserts (to avoid long transactions holding locks)</li></ul><p>✅ <strong>Chapter 0 Self-Assessment</strong></p><ol><li>In one sentence, explain why order-service does not directly connect to stock_db but uses Feign instead?</li><li>Which approach better reflects microservice boundaries: one instance with multiple schemas, or one instance with a single schema using table prefixes? Why?</li><li>If we decide to implement Redis distributed locks in the future, would our current strategy pattern design need to be changed?</li></ol><hr><p><strong>Next Chapter</strong>: <a href="./environment.html">Environment Preparation (Chapter 1)</a></p>`,32)])])}const u=t(i,[["render",r]]);export{g as __pageData,u as default};
